export const act2Content: Array<any> = [
  { type: 'scene', content: [{ type: 'text', text: 'ACT II - SCENE I. A room in Polonius\'s house.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Enter Polonius and Reynaldo.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Give him this money and these notes, Reynaldo.' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'I will, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'You shall do marvellous wisely, good Reynaldo, Before you visit him, to make inquiry Of his behaviour.' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'My lord, I did intend it.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Marry, well said; very well said. Look you, sir, Enquire me first what Danskers are in Paris; And how, and who, what means, and where they keep, What company, at what expense; and finding By this encompassment and drift of question, That they do know my son, come you more nearer Than your particular demands will touch it. Take you as \'twere some distant knowledge of him, As thus, \'I know his father and his friends, And in part him\'—do you mark this, Reynaldo?' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'Ay, very well, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: '\'And in part him, but,\' you may say, \'not well; But if\'t be he I mean, he\'s very wild; Addicted so and so;\' and there put on him What forgeries you please; marry, none so rank As may dishonour him; take heed of that; But, sir, such wanton, wild, and usual slips As are companions noted and most known To youth and liberty.' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'As gaming, my lord?' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Ay, or drinking, fencing, swearing, Quarrelling, drabbing. You may go so far.' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'My lord, that would dishonour him.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Faith no, as you may season it in the charge. You must not put another scandal on him, That he is open to incontinency; That\'s not my meaning: but breathe his faults so quaintly That they may seem the taints of liberty; The flash and outbreak of a fiery mind, A savageness in unreclaimed blood, Of general assault.' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'But my good lord—' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Wherefore should you do this?' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'Ay, my lord, I would know that.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Marry, sir, here\'s my drift, And I believe it is a fetch of warrant. You laying these slight sullies on my son, As \'twere a thing a little soil\'d i\' th\' working, Mark you, Your party in converse, him you would sound, Having ever seen in the prenominate crimes The youth you breathe of guilty, be assur\'d He closes with you in this consequence; \'Good sir,\' or so; or \'friend,\' or \'gentleman\'— According to the phrase or the addition Of man and country.' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'Very good, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'And then, sir, does he this,— He does—What was I about to say? By the mass, I was about to say something. Where did I leave?' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'At \'closes in the consequence.\' At \'friend or so,\' and \'gentleman.\'' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'At \'closes in the consequence\' ay, marry! He closes with you thus: \'I know the gentleman, I saw him yesterday, or t\'other day, Or then, or then, with such and such; and, as you say, There was he gaming, there o\'ertook in\'s rouse, There falling out at tennis\': or perchance, \'I saw him enter such a house of sale\'— Videlicet, a brothel, or so forth. See you now; Your bait of falsehood takes this carp of truth; And thus do we of wisdom and of reach, With windlasses, and with assays of bias, By indirections find directions out. So by my former lecture and advice Shall you my son. You have me, have you not?' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'My lord, I have.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'God b\' wi\' you, fare you well.' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'Good my lord.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Observe his inclination in yourself.' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'I shall, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'And let him ply his music.' }] },
  { type: 'dialogue', attrs: { character: 'REYNALDO' }, content: [{ type: 'text', text: 'Well, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Farewell.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Exit Reynaldo.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Enter Ophelia.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'How now, Ophelia, what\'s the matter?' }] },
  { type: 'dialogue', attrs: { character: 'OPHELIA' }, content: [{ type: 'text', text: 'Alas, my lord, I have been so affrighted.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'With what, in the name of God?' }] },
  { type: 'dialogue', attrs: { character: 'OPHELIA' }, content: [{ type: 'text', text: 'My lord, as I was sewing in my chamber, Lord Hamlet, with his doublet all unbrac\'d, No hat upon his head, his stockings foul\'d, Ungart\'red, and down-gyved to his ankle, Pale as his shirt, his knees knocking each other, And with a look so piteous in purport As if he had been loosed out of hell To speak of horrors, he comes before me.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Mad for thy love?' }] },
  { type: 'dialogue', attrs: { character: 'OPHELIA' }, content: [{ type: 'text', text: 'My lord, I do not know, but truly I do fear it.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'What said he?' }] },
  { type: 'dialogue', attrs: { character: 'OPHELIA' }, content: [{ type: 'text', text: 'He took me by the wrist and held me hard; Then goes he to the length of all his arm; And with his other hand thus o\'er his brow, He falls to such perusal of my face As he would draw it. Long stay\'d he so, At last,—a little shaking of mine arm, And thrice his head thus waving up and down, He rais\'d a sigh so piteous and profound As it did seem to shatter all his bulk And end his being. That done, he lets me go, And with his head over his shoulder turn\'d He seem\'d to find his way without his eyes, For out o\' doors he went without their help, And to the last bended their light on me.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Come, go with me. I will go seek the King. This is the very ecstasy of love, Whose violent property fordoes itself, And leads the will to desperate undertakings, As oft as any passion under heaven That does afflict our natures. I am sorry,— What, have you given him any hard words of late?' }] },
  { type: 'dialogue', attrs: { character: 'OPHELIA' }, content: [{ type: 'text', text: 'No, my good lord; but as you did command, I did repel his letters and denied His access to me.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'That hath made him mad. I am sorry that with better heed and judgement I had not quoted him. I fear\'d he did but trifle, And meant to wreck thee. But beshrew my jealousy! It seems it is as proper to our age To cast beyond ourselves in our opinions As it is common for the younger sort To lack discretion. Come, go we to the King. This must be known, which, being kept close, might move More grief to hide than hate to utter love.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Exeunt.' }] },
  { type: 'scene', content: [{ type: 'text', text: 'ACT II - SCENE II. A room in the Castle.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Enter King, Queen, Rosencrantz, Guildenstern and Attendants.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'Welcome, dear Rosencrantz and Guildenstern. Moreover that we much did long to see you, The need we have to use you did provoke Our hasty sending. Something have you heard Of Hamlet\'s transformation; so I call it, Since nor th\'exterior nor the inward man Resembles that it was. What it should be, More than his father\'s death, that thus hath put him So much from th\'understanding of himself, I cannot dream of. I entreat you both That, being of so young days brought up with him, And since so neighbour\'d to his youth and humour, That you vouchsafe your rest here in our court Some little time, so by your companies To draw him on to pleasures and to gather, So much as from occasion you may glean, Whether aught to us unknown afflicts him thus That, open\'d, lies within our remedy.' }] },
  { type: 'dialogue', attrs: { character: 'QUEEN' }, content: [{ type: 'text', text: 'Good gentlemen, he hath much talk\'d of you, And sure I am, two men there are not living To whom he more adheres. If it will please you To show us so much gentry and good will As to expend your time with us awhile, For the supply and profit of our hope, Your visitation shall receive such thanks As fits a king\'s remembrance.' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'Both your majesties Might, by the sovereign power you have of us, Put your dread pleasures more into command Than to entreaty.' }] },
  { type: 'dialogue', attrs: { character: 'GUILDENSTERN' }, content: [{ type: 'text', text: 'We both obey, And here give up ourselves, in the full bent, To lay our service freely at your feet To be commanded.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'Thanks, Rosencrantz and gentle Guildenstern.' }] },
  { type: 'dialogue', attrs: { character: 'QUEEN' }, content: [{ type: 'text', text: 'Thanks, Guildenstern and gentle Rosencrantz. And I beseech you instantly to visit My too much changed son. Go, some of you, And bring these gentlemen where Hamlet is.' }] },
  { type: 'dialogue', attrs: { character: 'GUILDENSTERN' }, content: [{ type: 'text', text: 'Heavens make our presence and our practices Pleasant and helpful to him.' }] },
  { type: 'dialogue', attrs: { character: 'QUEEN' }, content: [{ type: 'text', text: 'Ay, amen.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Exeunt Rosencrantz, Guildenstern and some Attendants.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Enter Polonius.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Th\'ambassadors from Norway, my good lord, Are joyfully return\'d.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'Thou still hast been the father of good news.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Have I, my lord? Assure you, my good liege, I hold my duty, as I hold my soul, Both to my God and to my gracious King: And I do think,—or else this brain of mine Hunts not the trail of policy so sure As it hath us\'d to do—that I have found The very cause of Hamlet\'s lunacy.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'O speak of that, that do I long to hear.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Give first admittance to th\'ambassadors; My news shall be the fruit to that great feast.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'Thyself do grace to them, and bring them in.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Exit Polonius.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'He tells me, my sweet queen, that he hath found The head and source of all your son\'s distemper.' }] },
  { type: 'dialogue', attrs: { character: 'QUEEN' }, content: [{ type: 'text', text: 'I doubt it is no other but the main, His father\'s death and our o\'erhasty marriage.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'Well, we shall sift him.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Enter Polonius with Voltemand and Cornelius.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'Welcome, my good friends! Say, Voltemand, what from our brother Norway?' }] },
  { type: 'dialogue', attrs: { character: 'VOLTEMAND' }, content: [{ type: 'text', text: 'Most fair return of greetings and desires. Upon our first, he sent out to suppress His nephew\'s levies, which to him appear\'d To be a preparation \'gainst the Polack; But better look\'d into, he truly found It was against your Highness; whereat griev\'d, That so his sickness, age, and impotence Was falsely borne in hand, sends out arrests On Fortinbras; which he, in brief, obeys, Receives rebuke from Norway; and in fine, Makes vow before his uncle never more To give th\'assay of arms against your Majesty. Whereon old Norway, overcome with joy, Gives him three thousand crowns in annual fee, And his commission to employ those soldiers So levied as before, against the Polack: With an entreaty, herein further shown, That it might please you to give quiet pass Through your dominions for this enterprise, On such regards of safety and allowance As therein are set down.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Gives a paper.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'It likes us well; And at our more consider\'d time we\'ll read, Answer, and think upon this business. Meantime we thank you for your well-took labour. Go to your rest, at night we\'ll feast together:. Most welcome home.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Exeunt Voltemand and Cornelius.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'This business is well ended. My liege and madam, to expostulate What majesty should be, what duty is, Why day is day, night night, and time is time Were nothing but to waste night, day and time. Therefore, since brevity is the soul of wit, And tediousness the limbs and outward flourishes, I will be brief. Your noble son is mad. Mad call I it; for to define true madness, What is\'t but to be nothing else but mad? But let that go.' }] },
  { type: 'dialogue', attrs: { character: 'QUEEN' }, content: [{ type: 'text', text: 'More matter, with less art.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Madam, I swear I use no art at all. That he is mad, \'tis true: \'tis true \'tis pity; And pity \'tis \'tis true. A foolish figure, But farewell it, for I will use no art. Mad let us grant him then. And now remains That we find out the cause of this effect, Or rather say, the cause of this defect, For this effect defective comes by cause. Thus it remains, and the remainder thus. Perpend, I have a daughter—have whilst she is mine— Who in her duty and obedience, mark, Hath given me this. Now gather, and surmise.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Reads.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'To the celestial, and my soul\'s idol, the most beautified Ophelia— That\'s an ill phrase, a vile phrase; \'beautified\' is a vile phrase: but you shall hear.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Reads.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'these; in her excellent white bosom, these, &c.' }] },
  { type: 'dialogue', attrs: { character: 'QUEEN' }, content: [{ type: 'text', text: 'Came this from Hamlet to her?' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Good madam, stay awhile; I will be faithful.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Reads.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Doubt thou the stars are fire, Doubt that the sun doth move, Doubt truth to be a liar, But never doubt I love. O dear Ophelia, I am ill at these numbers. I have not art to reckon my groans. But that I love thee best, O most best, believe it. Adieu. Thine evermore, most dear lady, whilst this machine is to him, HAMLET. This in obedience hath my daughter show\'d me; And more above, hath his solicitings, As they fell out by time, by means, and place, All given to mine ear.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'But how hath she receiv\'d his love?' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'What do you think of me?' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'As of a man faithful and honourable.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'I would fain prove so. But what might you think, When I had seen this hot love on the wing, As I perceiv\'d it, I must tell you that, Before my daughter told me, what might you, Or my dear Majesty your queen here, think, If I had play\'d the desk or table-book, Or given my heart a winking, mute and dumb, Or look\'d upon this love with idle sight, What might you think? No, I went round to work, And my young mistress thus I did bespeak: \'Lord Hamlet is a prince, out of thy star. This must not be.\' And then I precepts gave her, That she should lock herself from his resort, Admit no messengers, receive no tokens. Which done, she took the fruits of my advice, And he, repulsed,—a short tale to make— Fell into a sadness, then into a fast, Thence to a watch, thence into a weakness, Thence to a lightness, and, by this declension, Into the madness wherein now he raves, And all we wail for.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'Do you think \'tis this?' }] },
  { type: 'dialogue', attrs: { character: 'QUEEN' }, content: [{ type: 'text', text: 'It may be, very likely.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Hath there been such a time, I\'d fain know that, That I have positively said \'\'Tis so,\' When it prov\'d otherwise?' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'Not that I know.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Take this from this, if this be otherwise.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Points to his head and shoulder.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'If circumstances lead me, I will find Where truth is hid, though it were hid indeed Within the centre.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'How may we try it further?' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'You know sometimes he walks four hours together Here in the lobby.' }] },
  { type: 'dialogue', attrs: { character: 'QUEEN' }, content: [{ type: 'text', text: 'So he does indeed.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'At such a time I\'ll loose my daughter to him. Be you and I behind an arras then, Mark the encounter. If he love her not, And be not from his reason fall\'n thereon, Let me be no assistant for a state, But keep a farm and carters.' }] },
  { type: 'dialogue', attrs: { character: 'KING' }, content: [{ type: 'text', text: 'We will try it.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Enter Hamlet, reading.' }] },
  { type: 'dialogue', attrs: { character: 'QUEEN' }, content: [{ type: 'text', text: 'But look where sadly the poor wretch comes reading.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Away, I do beseech you, both away I\'ll board him presently. O, give me leave.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Exeunt King, Queen and Attendants.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'How does my good Lord Hamlet?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Well, God-a-mercy.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Do you know me, my lord?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Excellent well. You are a fishmonger.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Not I, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Then I would you were so honest a man.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Honest, my lord?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Ay sir, to be honest, as this world goes, is to be one man picked out of ten thousand.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'That\'s very true, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'For if the sun breed maggots in a dead dog, being a good kissing carrion,— Have you a daughter?' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'I have, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Let her not walk i\' th\' sun. Conception is a blessing, but not as your daughter may conceive. Friend, look to\'t.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'How say you by that?' }] },
  { type: 'action', content: [{ type: 'text', text: 'Aside.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Still harping on my daughter. Yet he knew me not at first; he said I was a fishmonger. He is far gone, far gone. And truly in my youth I suffered much extremity for love; very near this. I\'ll speak to him again.—What do you read, my lord?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Words, words, words.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'What is the matter, my lord?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Between who?' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'I mean the matter that you read, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Slanders, sir. For the satirical slave says here that old men have grey beards; that their faces are wrinkled; their eyes purging thick amber and plum-tree gum; and that they have a plentiful lack of wit, together with most weak hams. All which, sir, though I most powerfully and potently believe, yet I hold it not honesty to have it thus set down. For you yourself, sir, should be old as I am, if like a crab you could go backward.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Aside.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Though this be madness, yet there is method in\'t.— Will you walk out of the air, my lord?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Into my grave?' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Indeed, that is out o\' the air.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Aside.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'How pregnant sometimes his replies are! A happiness that often madness hits on, which reason and sanity could not so prosperously be delivered of. I will leave him and suddenly contrive the means of meeting between him and my daughter. My honourable lord, I will most humbly take my leave of you.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'You cannot, sir, take from me anything that I will more willingly part withal, except my life, except my life, except my life.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Fare you well, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'These tedious old fools.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Enter Rosencrantz and Guildenstern.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'You go to seek the Lord Hamlet; there he is.' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'God save you, sir.' }] },
  { type: 'action', content: [{ type: 'text', text: 'To Polonius.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Exit Polonius.' }] },
  { type: 'dialogue', attrs: { character: 'GUILDENSTERN' }, content: [{ type: 'text', text: 'My honoured lord!' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'My most dear lord!' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'My excellent good friends! How dost thou, Guildenstern? Ah, Rosencrantz. Good lads, how do ye both?' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'As the indifferent children of the earth.' }] },
  { type: 'dialogue', attrs: { character: 'GUILDENSTERN' }, content: [{ type: 'text', text: 'Happy in that we are not over-happy; On Fortune\'s cap we are not the very button.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Nor the soles of her shoe?' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'Neither, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Then you live about her waist, or in the middle of her favours?' }] },
  { type: 'dialogue', attrs: { character: 'GUILDENSTERN' }, content: [{ type: 'text', text: 'Faith, her privates we.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'In the secret parts of Fortune? O, most true; she is a strumpet. What\'s the news?' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'None, my lord, but that the world\'s grown honest.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Then is doomsday near. But your news is not true. Let me question more in particular. What have you, my good friends, deserved at the hands of Fortune, that she sends you to prison hither?' }] },
  { type: 'dialogue', attrs: { character: 'GUILDENSTERN' }, content: [{ type: 'text', text: 'Prison, my lord?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Denmark\'s a prison.' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'Then is the world one.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'A goodly one; in which there are many confines, wards, and dungeons, Denmark being one o\' th\' worst.' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'We think not so, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Why, then \'tis none to you; for there is nothing either good or bad but thinking makes it so. To me it is a prison.' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'Why, then your ambition makes it one; \'tis too narrow for your mind.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'O God, I could be bounded in a nutshell, and count myself a king of infinite space, were it not that I have bad dreams.' }] },
  { type: 'dialogue', attrs: { character: 'GUILDENSTERN' }, content: [{ type: 'text', text: 'Which dreams, indeed, are ambition; for the very substance of the ambitious is merely the shadow of a dream.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'A dream itself is but a shadow.' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'Truly, and I hold ambition of so airy and light a quality that it is but a shadow\'s shadow.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Then are our beggars bodies, and our monarchs and outstretch\'d heroes the beggars\' shadows. Shall we to th\' court? For, by my fay, I cannot reason.' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ and GUILDENSTERN' }, content: [{ type: 'text', text: 'We\'ll wait upon you.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'No such matter. I will not sort you with the rest of my servants; for, to speak to you like an honest man, I am most dreadfully attended. But, in the beaten way of friendship, what make you at Elsinore?' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'To visit you, my lord, no other occasion.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Beggar that I am, I am even poor in thanks; but I thank you. And sure, dear friends, my thanks are too dear a halfpenny. Were you not sent for? Is it your own inclining? Is it a free visitation? Come, deal justly with me. Come, come; nay, speak.' }] },
  { type: 'dialogue', attrs: { character: 'GUILDENSTERN' }, content: [{ type: 'text', text: 'What should we say, my lord?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Why, anything. But to the purpose. You were sent for; and there is a kind of confession in your looks, which your modesties have not craft enough to colour. I know the good King and Queen have sent for you.' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'To what end, my lord?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'That you must teach me. But let me conjure you, by the rights of our fellowship, by the consonancy of our youth, by the obligation of our ever-preserved love, and by what more dear a better proposer could charge you withal, be even and direct with me, whether you were sent for or no.' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'What say you?' }] },
  { type: 'action', content: [{ type: 'text', text: 'To Guildenstern.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Nay, then I have an eye of you. If you love me, hold not off.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Aside.' }] },
  { type: 'dialogue', attrs: { character: 'GUILDENSTERN' }, content: [{ type: 'text', text: 'My lord, we were sent for.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'I will tell you why; so shall my anticipation prevent your discovery, and your secrecy to the King and Queen moult no feather. I have of late, but wherefore I know not, lost all my mirth, forgone all custom of exercises; and indeed, it goes so heavily with my disposition that this goodly frame the earth, seems to me a sterile promontory; this most excellent canopy the air, look you, this brave o\'erhanging firmament, this majestical roof fretted with golden fire, why, it appears no other thing to me than a foul and pestilent congregation of vapours. What a piece of work is man, how noble in reason, how infinite in faculties, in form and moving, how express and admirable; in action how like an angel, in apprehension, how like a god: the beauty of the world, the paragon of animals. And yet, to me, what is this quintessence of dust? Man delights not me; no, nor woman neither, though by your smiling you seem to say so.' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'My lord, there was no such stuff in my thoughts.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Why did you laugh then, when I said \'Man delights not me\'?' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'To think, my lord, if you delight not in man, what Lenten entertainment the players shall receive from you. We coted them on the way, and hither are they coming to offer you service.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'He that plays the king shall be welcome,—his Majesty shall have tribute of me; the adventurous knight shall use his foil and target; the lover shall not sigh gratis, the humorous man shall end his part in peace; the clown shall make those laugh whose lungs are tickle o\' th\' sere; and the lady shall say her mind freely, or the blank verse shall halt for\'t. What players are they?' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'Even those you were wont to take such delight in—the tragedians of the city.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'How chances it they travel? Their residence, both in reputation and profit, was better both ways.' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'I think their inhibition comes by the means of the late innovation.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Do they hold the same estimation they did when I was in the city? Are they so followed?' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'No, indeed, they are not.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'How comes it? Do they grow rusty?' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'Nay, their endeavour keeps in the wonted pace; but there is, sir, an aerie of children, little eyases, that cry out on the top of question, and are most tyrannically clapped for\'t. These are now the fashion, and so berattle the common stages—so they call them—that many wearing rapiers are afraid of goose-quills and dare scarce come thither.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'What, are they children? Who maintains \'em? How are they escoted? Will they pursue the quality no longer than they can sing? Will they not say afterwards, if they should grow themselves to common players—as it is most like, if their means are no better—their writers do them wrong to make them exclaim against their own succession?' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'Faith, there has been much to do on both sides; and the nation holds it no sin to tarre them to controversy. There was for a while, no money bid for argument unless the poet and the player went to cuffs in the question.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Is\'t possible?' }] },
  { type: 'dialogue', attrs: { character: 'GUILDENSTERN' }, content: [{ type: 'text', text: 'O, there has been much throwing about of brains.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Do the boys carry it away?' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'Ay, that they do, my lord. Hercules and his load too.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'It is not very strange; for my uncle is King of Denmark, and those that would make mouths at him while my father lived, give twenty, forty, fifty, a hundred ducats apiece for his picture in little. \'Sblood, there is something in this more than natural, if philosophy could find it out.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Flourish of trumpets within.' }] },
  { type: 'dialogue', attrs: { character: 'GUILDENSTERN' }, content: [{ type: 'text', text: 'There are the players.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Gentlemen, you are welcome to Elsinore. Your hands, come. The appurtenance of welcome is fashion and ceremony. Let me comply with you in this garb, lest my extent to the players, which I tell you must show fairly outward, should more appear like entertainment than yours. You are welcome. But my uncle-father and aunt-mother are deceived.' }] },
  { type: 'dialogue', attrs: { character: 'GUILDENSTERN' }, content: [{ type: 'text', text: 'In what, my dear lord?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'I am but mad north-north-west. When the wind is southerly, I know a hawk from a handsaw.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Enter Polonius.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Well be with you, gentlemen.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Hark you, Guildenstern, and you too, at each ear a hearer. That great baby you see there is not yet out of his swaddling clouts.' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'Happily he\'s the second time come to them; for they say an old man is twice a child.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'I will prophesy he comes to tell me of the players. Mark it.—You say right, sir: for a Monday morning \'twas so indeed.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'My lord, I have news to tell you.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'My lord, I have news to tell you. When Roscius was an actor in Rome—' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'The actors are come hither, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Buzz, buzz.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Upon my honour.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Then came each actor on his ass—' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'The best actors in the world, either for tragedy, comedy, history, pastoral, pastoral-comical, historical-pastoral, tragical-historical, tragical-comical-historical-pastoral, scene individable, or poem unlimited. Seneca cannot be too heavy, nor Plautus too light, for the law of writ and the liberty. These are the only men.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'O Jephthah, judge of Israel, what a treasure hadst thou!' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'What treasure had he, my lord?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Why— \'One fair daughter, and no more, The which he loved passing well.\'' }] },
  { type: 'action', content: [{ type: 'text', text: 'Aside.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Still on my daughter.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Am I not i\' th\' right, old Jephthah?' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'If you call me Jephthah, my lord, I have a daughter that I love passing well.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Nay, that follows not.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'What follows then, my lord?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Why, As by lot, God wot, and then, you know, It came to pass, as most like it was. The first row of the pious chanson will show you more. For look where my abridgement comes.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Enter four or five Players.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'You are welcome, masters, welcome all. I am glad to see thee well. Welcome, good friends. O, my old friend! Thy face is valanc\'d since I saw thee last. Com\'st thou to beard me in Denmark? What, my young lady and mistress! By\'r lady, your ladyship is nearer to heaven than when I saw you last, by the altitude of a chopine. Pray God your voice, like a piece of uncurrent gold, be not cracked within the ring. Masters, you are all welcome. We\'ll e\'en to\'t like French falconers, fly at anything we see. We\'ll have a speech straight. Come, give us a taste of your quality. Come, a passionate speech.' }] },
  { type: 'dialogue', attrs: { character: 'PLAYER' }, content: [{ type: 'text', text: 'What speech, my lord?' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'I heard thee speak me a speech once, but it was never acted, or if it was, not above once, for the play, I remember, pleased not the million, \'twas caviare to the general. But it was—as I received it, and others, whose judgements in such matters cried in the top of mine—an excellent play, well digested in the scenes, set down with as much modesty as cunning. I remember one said there were no sallets in the lines to make the matter savoury, nor no matter in the phrase that might indite the author of affectation, but called it an honest method, as wholesome as sweet, and by very much more handsome than fine. One speech in it, I chiefly loved. \'Twas Aeneas\' tale to Dido, and thereabout of it especially where he speaks of Priam\'s slaughter. If it live in your memory, begin at this line, let me see, let me see: The rugged Pyrrhus, like th\' Hyrcanian beast,— It is not so: it begins with Pyrrhus— The rugged Pyrrhus, he whose sable arms, Black as his purpose, did the night resemble When he lay couched in the ominous horse, Hath now this dread and black complexion smear\'d With heraldry more dismal. Head to foot Now is he total gules, horridly trick\'d With blood of fathers, mothers, daughters, sons, Bak\'d and impasted with the parching streets, That lend a tyrannous and a damned light To their vile murders. Roasted in wrath and fire, And thus o\'ersized with coagulate gore, With eyes like carbuncles, the hellish Pyrrhus Old grandsire Priam seeks. So, proceed you.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: '\'Fore God, my lord, well spoken, with good accent and good discretion.' }] },
  { type: 'dialogue', attrs: { character: 'PLAYER' }, content: [{ type: 'text', text: 'Anon he finds him, Striking too short at Greeks. His antique sword, Rebellious to his arm, lies where it falls, Repugnant to command. Unequal match\'d, Pyrrhus at Priam drives, in rage strikes wide; But with the whiff and wind of his fell sword Th\'unnerved father falls. Then senseless Ilium, Seeming to feel this blow, with flaming top Stoops to his base, and with a hideous crash Takes prisoner Pyrrhus\' ear. For lo, his sword, Which was declining on the milky head Of reverend Priam, seem\'d i\' th\'air to stick. So, as a painted tyrant, Pyrrhus stood, And like a neutral to his will and matter, Did nothing. But as we often see against some storm, A silence in the heavens, the rack stand still, The bold winds speechless, and the orb below As hush as death, anon the dreadful thunder Doth rend the region; so after Pyrrhus\' pause, Aroused vengeance sets him new a-work, And never did the Cyclops\' hammers fall On Mars\'s armour, forg\'d for proof eterne, With less remorse than Pyrrhus\' bleeding sword Now falls on Priam. Out, out, thou strumpet Fortune! All you gods, In general synod, take away her power; Break all the spokes and fellies from her wheel, And bowl the round nave down the hill of heaven, As low as to the fiends.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'This is too long.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'It shall to the barber\'s, with your beard.—Prithee say on. He\'s for a jig or a tale of bawdry, or he sleeps. Say on; come to Hecuba.' }] },
  { type: 'dialogue', attrs: { character: 'PLAYER' }, content: [{ type: 'text', text: 'But who, O who, had seen the mobled queen,—' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: '\'The mobled queen\'?' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'That\'s good! \'Mobled queen\' is good.' }] },
  { type: 'dialogue', attrs: { character: 'PLAYER' }, content: [{ type: 'text', text: 'Run barefoot up and down, threat\'ning the flames With bisson rheum. A clout upon that head Where late the diadem stood, and for a robe, About her lank and all o\'erteemed loins, A blanket, in th\'alarm of fear caught up— Who this had seen, with tongue in venom steep\'d, \'Gainst Fortune\'s state would treason have pronounc\'d. But if the gods themselves did see her then, When she saw Pyrrhus make malicious sport In mincing with his sword her husband\'s limbs, The instant burst of clamour that she made,— Unless things mortal move them not at all,— Would have made milch the burning eyes of heaven, And passion in the gods.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Look, where he has not turn\'d his colour, and has tears in\'s eyes. Pray you, no more.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: '\'Tis well. I\'ll have thee speak out the rest of this soon.—Good my lord, will you see the players well bestowed? Do you hear, let them be well used; for they are the abstracts and brief chronicles of the time. After your death you were better have a bad epitaph than their ill report while you live.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'My lord, I will use them according to their desert.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'God\'s bodikin, man, much better. Use every man after his desert, and who should \'scape whipping? Use them after your own honour and dignity. The less they deserve, the more merit is in your bounty. Take them in.' }] },
  { type: 'dialogue', attrs: { character: 'POLONIUS' }, content: [{ type: 'text', text: 'Come, sirs.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Follow him, friends. We\'ll hear a play tomorrow.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Exeunt Polonius with all the Players but the First.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Dost thou hear me, old friend? Can you play The Murder of Gonzago?' }] },
  { type: 'dialogue', attrs: { character: 'PLAYER' }, content: [{ type: 'text', text: 'Ay, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'We\'ll ha\'t tomorrow night. You could for a need study a speech of some dozen or sixteen lines, which I would set down and insert in\'t, could you not?' }] },
  { type: 'dialogue', attrs: { character: 'PLAYER' }, content: [{ type: 'text', text: 'Ay, my lord.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Very well. Follow that lord, and look you mock him not.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Exit First Player.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'My good friends, I\'ll leave you till night. You are welcome to Elsinore.' }] },
  { type: 'action', content: [{ type: 'text', text: 'To Rosencrantz and Guildenstern' }] },
  { type: 'dialogue', attrs: { character: 'ROSENCRANTZ' }, content: [{ type: 'text', text: 'Good my lord.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Exeunt Rosencrantz and Guildenstern.' }] },
  { type: 'dialogue', attrs: { character: 'HAMLET' }, content: [{ type: 'text', text: 'Ay, so, God b\' wi\' ye. Now I am alone. O what a rogue and peasant slave am I! Is it not monstrous that this player here, But in a fiction, in a dream of passion, Could force his soul so to his own conceit That from her working all his visage wan\'d; Tears in his eyes, distraction in\'s aspect, A broken voice, and his whole function suiting With forms to his conceit? And all for nothing! For Hecuba? What\'s Hecuba to him, or he to Hecuba, That he should weep for her? What would he do, Had he the motive and the cue for passion That I have? He would drown the stage with tears And cleave the general ear with horrid speech; Make mad the guilty, and appal the free, Confound the ignorant, and amaze indeed, The very faculties of eyes and ears. Yet I, A dull and muddy-mettled rascal, peak Like John-a-dreams, unpregnant of my cause, And can say nothing. No, not for a king Upon whose property and most dear life A damn\'d defeat was made. Am I a coward? Who calls me villain, breaks my pate across? Plucks off my beard and blows it in my face? Tweaks me by the nose, gives me the lie i\' th\' throat As deep as to the lungs? Who does me this? Ha! \'Swounds, I should take it: for it cannot be But I am pigeon-liver\'d, and lack gall To make oppression bitter, or ere this I should have fatted all the region kites With this slave\'s offal. Bloody, bawdy villain! Remorseless, treacherous, lecherous, kindless villain! Oh vengeance! Why, what an ass am I! This is most brave, That I, the son of a dear father murder\'d, Prompted to my revenge by heaven and hell, Must, like a whore, unpack my heart with words And fall a-cursing like a very drab, A scullion! Fie upon\'t! Foh! About, my brain! I have heard That guilty creatures sitting at a play, Have by the very cunning of the scene, Been struck so to the soul that presently They have proclaim\'d their malefactions. For murder, though it have no tongue, will speak With most miraculous organ. I\'ll have these players Play something like the murder of my father Before mine uncle. I\'ll observe his looks; I\'ll tent him to the quick. If he but blench, I know my course. The spirit that I have seen May be the devil, and the devil hath power T\'assume a pleasing shape, yea, and perhaps Out of my weakness and my melancholy, As he is very potent with such spirits, Abuses me to damn me. I\'ll have grounds More relative than this. The play\'s the thing Wherein I\'ll catch the conscience of the King.' }] },
  { type: 'action', content: [{ type: 'text', text: 'Exit.' }] },
  { type: 'transition', content: [{ type: 'text', text: 'END OF ACT II' }] }
]
